INSERT INTO articles (slug, title, content, source, category) VALUES
('dao-de-jing-chapter-41', '道德经·第四十一章', '上士闻道，勤而行之；中士闻道，若存若亡；下士闻道，大笑之。不笑不足以为道。故建言有之：明道若昧；进道若退；夷道若颣；上德若谷；广德若不足；建德若偷；质真若渝；大白若辱；大方无隅；大器晚成；大音希声；大象无形；道隐无名。夫唯道，善贷且成。', '老子', 'classics'),
('dao-de-jing-chapter-42', '道德经·第四十二章', '道生一，一生二，二生三，三生万物。万物负阴而抱阳，冲气以为和。人之所恶，唯孤、寡、不谷，而王公以为称。故物或损之而益，或益之而损。人之所教，我亦教之。强梁者不得其死，吾将以为教父。', '老子', 'classics'),
('dao-de-jing-chapter-43', '道德经·第四十三章', '天下之至柔，驰骋天下之至坚。无有入无间，吾是以知无为之有益。不言之教，无为之益，天下希及之。', '老子', 'classics'),
('dao-de-jing-chapter-44', '道德经·第四十四章', '名与身孰亲？身与货孰多？得与亡孰病？甚爱必大费；多藏必厚亡。故知足不辱，知止不殆，可以长久。', '老子', 'classics'),
('dao-de-jing-chapter-45', '道德经·第四十五章', '大成若缺，其用不弊。大盈若冲，其用不穷。大直若屈，大巧若拙，大辩若讷。躁胜寒，静胜热。清静为天下正。', '老子', 'classics'),
('dao-de-jing-chapter-46', '道德经·第四十六章', '天下有道，却走马以粪。天下无道，戎马生于郊。祸莫大于不知足；咎莫大于欲得。故知足之足，常足矣。', '老子', 'classics'),
('dao-de-jing-chapter-47', '道德经·第四十七章', '不出户，知天下；不窥牖，见天道。其出弥远，其知弥少。是以圣人不行而知，不见而明，不为而成。', '老子', 'classics'),
('dao-de-jing-chapter-48', '道德经·第四十八章', '为学日益，为道日损。损之又损，以至于无为。无为而无不为。取天下常以无事，及其有事，不足以取天下。', '老子', 'classics'),
('dao-de-jing-chapter-49', '道德经·第四十九章', '圣人常无心，以百姓心为心。善者，吾善之；不善者，吾亦善之，德善。信者，吾信之；不信者，吾亦信之，德信。圣人在天下，歙歙焉，为天下浑其心，百姓皆注其耳目，圣人皆孩之。', '老子', 'classics'),
('dao-de-jing-chapter-50', '道德经·第五十章', '出生入死。生之徒，十有三；死之徒，十有三；人之生，动之于死地，亦十有三。夫何故？以其生之厚。盖闻善摄生者，路行不遇兕虎，入军不被甲兵；兕无所投其角，虎无所用其爪，兵无所容其刃。夫何故？以其无死地。', '老子', 'classics');